import json
from kafka import KafkaConsumer, KafkaProducer

class KafkaParser:
    def __init__(self, input_topic, output_topic, kafka_servers):
        self.consumer = KafkaConsumer(input_topic, bootstrap_servers=kafka_servers)
        self.producer = KafkaProducer(bootstrap_servers=kafka_servers)

    def parse_record(self, record):
        try:
            json_record = json.loads(record)
            return len(json_record)  # Return the number of keys in the JSON object
        except json.JSONDecodeError:
            return 0  # Return 0 if the record is not valid JSON

    def process_records(self):
        for message in self.consumer:
            count = self.parse_record(message.value.decode('utf-8'))
            self.producer.send(output_topic, str(count).encode('utf-8'))

def solve(input_topic, output_topic, kafka_servers):
    parser = KafkaParser(input_topic, output_topic, kafka_servers)
    parser.process_records()
